const item = $input.first().json;
const alert = $('Webhook Alerta Wazuh').first().json.body;

const level = parseInt(alert?.rule?.level ?? 0);
const description = alert?.rule?.description ?? 'Regla desconocida';
const agentName = alert?.agent?.name ?? 'desconocido';
const agentId = alert?.agent?.id ?? 'N/A';
const agentIp = alert?.agent?.ip ?? 'N/A';
const srcIp = alert?.data?.srcip ?? null;
const dstUser = alert?.data?.dstuser ?? null;
const srcUser = alert?.data?.srcuser ?? null;
const command = alert?.data?.command ?? null;
const groups = Array.isArray(alert?.rule?.groups) ? alert.rule.groups.join(', ') : (alert?.rule?.groups ?? 'N/A');
const ruleId = alert?.rule?.id ?? 'N/A';
const location = alert?.location ?? 'N/A';
const rawTs = alert?.timestamp ?? new Date().toISOString();
const tz = item.timezone ?? 'Europe/Madrid';
const ts = new Date(rawTs).toLocaleString('es-ES', { timeZone: tz, hour12: false });
const isCritical = level >= (item.criticalLevel ?? 12);

// ============================================================
// PERSONALIZA ESTO: Contexto de infraestructura NigulSystems
// Sustituye con tus IPs reales, hostnames, clientes y servicios
// ============================================================
const infraContext = `Contexto de infraestructura — NigulSystems MSP (wazuh.nigulsystems.net):
- MSP basado en España (Tortosa, Catalunya). Gestiona clientes SMB con 80-100+ agentes Wazuh.
- SIEM: Wazuh cluster en wazuh.nigulsystems.net — alertas de múltiples clientes
- Infraestructura propia: Proxmox VE con KVM/LXC, almacenamiento Ceph
- Servicios: n8n (n8n.nigul.info), Plesk, Docker/Portainer, WordPress/WooCommerce
- Red: protegida con Cloudflare, VPN interna para administración
- Respuesta activa: MONITORIZACIÓN PASIVA, sin bloqueo automático
- IMPORTANTE: identificar si la alerta pertenece a infraestructura propia del MSP o a un cliente gestionado
- agentName puede contener el nombre del cliente o del host del MSP`;
// ============================================================
// FIN PERSONALIZA — añade aquí IPs, rangos, clientes reales
// ============================================================

const systemPrompt = `Eres un analista de seguridad senior del MSP NigulSystems revisando una alerta del SIEM Wazuh. Responde SOLO con un objeto JSON válido, sin texto fuera del JSON, sin bloques de código markdown.

${infraContext}

Esquema de respuesta (todos los campos obligatorios):
{
  "risk_level": "low|medium|high|critical",
  "likely_cause": "una frase explicando la causa más probable dada esta infraestructura MSP",
  "is_likely_false_positive": true o false,
  "fp_reason": "si es falso positivo, razón breve; si no, cadena vacía",
  "client_or_msp": "nombre del cliente o 'MSP' si es infraestructura propia",
  "recommended_action": ["acción 1", "acción 2"],
  "investigate_commands": ["comando bash 1", "comando bash 2"],
  "ntfy_title": "título corto para notificación push (máx 50 chars)",
  "ntfy_tags": "emoji1,emoji2 (máx 2, ej: warning,skull)"
}`;

const userPrompt = `Analiza esta alerta de Wazuh del MSP NigulSystems:

Agente: ${agentName} (ID: ${agentId}, IP: ${agentIp})
Regla ID: ${ruleId} | Nivel: ${level} | Crítico: ${isCritical}
Descripción: ${description}
Grupos: ${groups}
IP Origen: ${srcIp ?? 'N/A'}
Usuario Destino: ${dstUser ?? 'N/A'} | Usuario Origen: ${srcUser ?? 'N/A'}
Comando: ${command ?? 'N/A'}
Ubicación (log): ${location}
Timestamp: ${ts}

JSON completo de la alerta:
${JSON.stringify(alert, null, 2)}`;

const aiRequestBody = {
  model: item.aiModel ?? 'claude-haiku-4-5-20251001',
  max_tokens: 800,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{
  json: {
    minAlertLevel: item.minAlertLevel,
    criticalLevel: item.criticalLevel,
    timezone: item.timezone,
    aiModel: item.aiModel,
    emailTo: item.emailTo,
    emailSubjectPrefix: item.emailSubjectPrefix,
    ntfyUrl: item.ntfyUrl,
    wazuhDashboard: item.wazuhDashboard,
    level, description, agentName, agentId, agentIp, srcIp, dstUser, srcUser, command, groups, ruleId, location, ts, isCritical,
    aiRequestBody
  }
}];

const item = $input.first().json;
const prev = $('Extraer Alerta').first().json;

let aiResult = {};
try {
  const rawContent = item?.choices?.[0]?.message?.content ?? '{}';
  const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiResult = JSON.parse(cleaned);
} catch(e) {
  aiResult = {
    risk_level: 'unknown',
    likely_cause: 'Error al parsear respuesta IA: ' + e.message,
    is_likely_false_positive: false,
    fp_reason: '',
    client_or_msp: 'Desconocido',
    recommended_action: ['Revisar manualmente en Wazuh Dashboard'],
    investigate_commands: [],
    ntfy_title: 'Error análisis IA',
    ntfy_tags: 'warning'
  };
}

const isFP = aiResult.is_likely_false_positive === true;
const riskLevel = (aiResult.risk_level ?? 'unknown').toUpperCase();
const riskEmoji = {CRITICAL: '🔴', HIGH: '🟠', MEDIUM: '🟡', LOW: '🟢', UNKNOWN: '⚪'}[riskLevel] ?? '⚪';
const fpBadge = isFP ? ' [PROBABLE FP]' : '';

const emailSubject = `${prev.emailSubjectPrefix} ${riskEmoji} ${riskLevel}${fpBadge} | Nivel ${prev.level} | ${prev.agentName} | ${prev.description.substring(0, 60)}`;

const riskColor = {CRITICAL:'#dc2626',HIGH:'#ea580c',MEDIUM:'#d97706',LOW:'#16a34a',UNKNOWN:'#6b7280'}[riskLevel] ?? '#6b7280';

const emailHtml = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><style>
body{font-family:Arial,sans-serif;background:#f5f5f5;margin:0;padding:20px}
.container{background:#fff;border-radius:8px;padding:24px;max-width:700px;margin:0 auto;border-left:5px solid ${riskColor}}
h2{margin:0 0 16px;color:#1e293b}
.badge{display:inline-block;padding:4px 12px;border-radius:20px;font-weight:bold;color:#fff;background:${riskColor}}
.fp{background:#7c3aed;color:#fff;padding:4px 10px;border-radius:20px;margin-left:8px;font-size:12px}
table{width:100%;border-collapse:collapse;margin:16px 0}
td{padding:8px 12px;border-bottom:1px solid #e2e8f0;vertical-align:top}
td:first-child{font-weight:bold;color:#475569;width:160px;white-space:nowrap}
.section-title{font-weight:bold;color:#1e293b;margin:16px 0 8px;font-size:14px;text-transform:uppercase;letter-spacing:0.05em}
.cmd{background:#1e293b;color:#a3e635;padding:8px 12px;border-radius:4px;font-family:monospace;font-size:12px;margin:4px 0;word-break:break-all}
.footer{margin-top:20px;padding-top:16px;border-top:1px solid #e2e8f0;font-size:12px;color:#94a3b8}
</style></head>
<body>
<div class="container">
  <h2>🛡️ NigulSystems NOC — Alerta Wazuh</h2>
  <span class="badge">${riskEmoji} ${riskLevel}</span>
  ${isFP ? '<span class="fp">PROBABLE FALSO POSITIVO</span>' : ''}
  <table>
    <tr><td>Agente</td><td><strong>${prev.agentName}</strong> (${prev.agentIp})</td></tr>
    <tr><td>Cliente/MSP</td><td>${aiResult.client_or_msp ?? 'N/A'}</td></tr>
    <tr><td>Regla</td><td>${prev.ruleId} — Nivel ${prev.level}</td></tr>
    <tr><td>Descripción</td><td>${prev.description}</td></tr>
    <tr><td>Grupos</td><td>${prev.groups}</td></tr>
    ${prev.srcIp ? `<tr><td>IP Origen</td><td>${prev.srcIp}</td></tr>` : ''}
    ${prev.srcUser ? `<tr><td>Usuario</td><td>${prev.srcUser}</td></tr>` : ''}
    <tr><td>Log</td><td>${prev.location}</td></tr>
    <tr><td>Timestamp</td><td>${prev.ts}</td></tr>
  </table>
  <div class="section-title">🤖 Análisis IA (${prev.aiModel})</div>
  <p><strong>Causa probable:</strong> ${aiResult.likely_cause ?? 'N/A'}</p>
  ${isFP && aiResult.fp_reason ? `<p><strong>Razón FP:</strong> ${aiResult.fp_reason}</p>` : ''}
  ${Array.isArray(aiResult.recommended_action) && aiResult.recommended_action.length > 0 ? `<div class="section-title">📋 Acciones Recomendadas</div><ul>${aiResult.recommended_action.map(a => `<li>${a}</li>`).join('')}</ul>` : ''}
  ${Array.isArray(aiResult.investigate_commands) && aiResult.investigate_commands.length > 0 ? `<div class="section-title">🔍 Comandos de Investigación</div>${aiResult.investigate_commands.map(c => `<div class="cmd">${c}</div>`).join('')}` : ''}
  <div class="footer">
    <a href="${prev.wazuhDashboard}">🔗 Abrir Wazuh Dashboard</a> |
    NigulSystems NOC AI Analyzer | ${prev.ts}
  </div>
</div>
</body></html>`;

const ntfyTitle = aiResult.ntfy_title ?? `${riskLevel} | ${prev.agentName}`;
const ntfyTags = aiResult.ntfy_tags ?? (riskLevel === 'CRITICAL' ? 'skull,rotating_light' : 'warning');
const ntfyPriority = {CRITICAL: 5, HIGH: 4, MEDIUM: 3, LOW: 2, UNKNOWN: 3}[riskLevel] ?? 3;
const ntfyBody = `${riskEmoji} [Nivel ${prev.level}] ${prev.agentName} (${prev.agentIp})
${prev.description}
${isFP ? '⚠️ PROBABLE FALSO POSITIVO: ' + (aiResult.fp_reason ?? '') : ''}
Causa: ${aiResult.likely_cause ?? 'N/A'}
Acción: ${Array.isArray(aiResult.recommended_action) ? aiResult.recommended_action[0] : 'Ver email'}`;

return [{
  json: {
    ...prev,
    aiResult,
    riskLevel,
    riskEmoji,
    isFP,
    emailSubject,
    emailHtml,
    ntfyTitle,
    ntfyTags,
    ntfyPriority,
    ntfyBody
  }
}];
